exercises.expected_solution:
import java.util.ArrayList;
import java.util.List;

class Point {
    int x, y;
    Point(int x, int y) { this.x = x; this.y = y; }
    double distanceFromOrigin() { return Math.sqrt(x * x + y * y); }
    public String toString() { return "(" + x + "," + y + ")"; }
}

public class App {
    public static void main(String[] args) {
        List<Point> points = new ArrayList<>();
        points.add(new Point(0, 3));
        points.add(new Point(2, 1));
        points.add(new Point(4, 4));
        points.add(new Point(1, 5));

        for (Point p : points) System.out.println(p);

        Point closest = points.get(0);
        for (Point p : points) {
            if (p.distanceFromOrigin() < closest.distanceFromOrigin()) {
                closest = p;
            }
        }
        System.out.println("Closest to origin: " + closest);
    }
}

