class CartItem {
    String productName;
    double price;
    int qty;

    CartItem(String productName, double price, int qty) {
        this.productName = productName; this.price = price; this.qty = qty;
    }

    double lineTotal() { return price * qty; }

    public String toString() {
        return productName + " x" + qty + " = ₹" + lineTotal();
    }
}

class ShoppingCart {
    private List<CartItem> items = new ArrayList<>();

    public void addItem(CartItem item) { items.add(item); }

    public void removeByName(String name) {
        items.removeIf(item -> item.productName.equals(name));
    }

    public double totalPrice() {
        double total = 0;
        for (CartItem item : items) total += item.lineTotal();
        return total;
    }

    public void printReceipt() {
        for (CartItem item : items) System.out.println(item);
        System.out.println("TOTAL: ₹" + totalPrice());
    }
}

public class App {
    public static void main(String[] args) {
        ShoppingCart cart = new ShoppingCart();
        cart.addItem(new CartItem("Wireless Mouse", 719.1, 1));
        cart.addItem(new CartItem("Keyboard", 1999.0, 2));
        cart.addItem(new CartItem("USB Hub", 499.0, 3));
        cart.printReceipt();
