// Contact class and ContactManager with List<Contact>

exercises.expected_solution:
import java.util.ArrayList;
import java.util.List;

class Contact {
    String name, phone, email;
    Contact(String name, String phone, String email) {
        this.name = name; this.phone = phone; this.email = email;
    }
    public String toString() { return name; }
}

class ContactManager {
    private List<Contact> contacts = new ArrayList<>();

    public void add(Contact c) {
        if (c.name == null || c.name.isBlank()) throw new IllegalArgumentException("Name required");
        contacts.add(c);
    }

    public void removeByEmail(String email) {
        contacts.removeIf(c -> c.email.equalsIgnoreCase(email));
    }

    public List<Contact> findByName(String query) {
        List<Contact> result = new ArrayList<>();
        for (Contact c : contacts) {
            if (c.name.toLowerCase().contains(query.toLowerCase())) {
                result.add(c);
            }
        }
        return result;
    }

    public void sortByName() {
        contacts.sort((a, b) -> a.name.compareTo(b.name));
    }

    public int countByDomain(String domain) {
        int count = 0;
        for (Contact c : contacts) {
            int at = c.email.indexOf('@');
            if (at >= 0 && c.email.substring(at + 1).equalsIgnoreCase(domain)) count++;
        }
        return count;
    }
}

public class App {
    public static void main(String[] args) {
        ContactManager cm = new ContactManager();
        cm.add(new Contact("Aisha Khan", "9876543210", "aisha@gmail.com"));
        cm.add(new Contact("Raj Kumar", "8765432109", "raj@company.com"));
        cm.add(new Contact("Priya Rao", "7654321098", "priya@gmail.com"));
        cm.add(new Contact("Vikram Singh", "6543210987", "vikram@yahoo.com"));
        cm.add(new Contact("Anita Das", "5432109876", "anita@company.com"));

        cm.removeByEmail("anita@company.com");

        List<Contact> found = cm.findByName("ra");
        System.out.print("Found " + found.size() + " with 'ra': ");
        for (int i = 0; i < found.size(); i++) {
            if (i > 0) System.out.print(", ");
            System.out.print(found.get(i).name);
        }
        System.out.println();

        System.out.println("gmail.com contacts: " + cm.countByDomain("gmail.com"));
    }
}

