// Three utility methods for List<Integer> analysis

exercises.expected_solution:
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class App {
    static double average(List<Integer> scores) {
        int sum = 0;
        for (int s : scores) sum += s;
        return (double) sum / scores.size();
    }

    static int countAbove(List<Integer> scores, int threshold) {
        int count = 0;
        for (int s : scores) if (s > threshold) count++;
        return count;
    }

    static List<Integer> topN(List<Integer> scores, int n) {
        List<Integer> sorted = new ArrayList<>(scores);  // copy
        sorted.sort((a, b) -> b - a);  // descending
        return sorted.subList(0, Math.min(n, sorted.size()));
    }

    public static void main(String[] args) {
        List<Integer> scores = new ArrayList<>();
        int[] raw = {72, 88, 91, 65, 78, 95, 83, 67, 91, 79};
        for (int s : raw) scores.add(s);

        System.out.println("Average: " + average(scores));
        System.out.println("Above 80: " + countAbove(scores, 80));
        System.out.println("Top 3: " + topN(scores, 3));
    }
}

