// Abstract Notification hierarchy + NotificationQueue with List<Notification>

exercises.expected_solution:
import java.util.ArrayList;
import java.util.List;

abstract class Notification {
    protected String message;
    Notification(String message) { this.message = message; }
    public abstract void deliver();
    public abstract int getPriority();
}

class EmailNotification extends Notification {
    EmailNotification(String message) { super(message); }
    @Override public void deliver() { System.out.println("[EMAIL-P3] " + message); }
    @Override public int getPriority() { return 3; }
}

class SMSNotification extends Notification {
    SMSNotification(String message) { super(message); }
    @Override public void deliver() { System.out.println("[SMS-P2] " + message); }
    @Override public int getPriority() { return 2; }
}

class PushNotification extends Notification {
    PushNotification(String message) { super(message); }
    @Override public void deliver() { System.out.println("[PUSH-P1] " + message); }
    @Override public int getPriority() { return 1; }
}

class NotificationQueue {
    private List<Notification> queue = new ArrayList<>();

    public void enqueue(Notification n) { queue.add(n); }

    public void deliverAll() {
        queue.sort((a, b) -> Integer.compare(a.getPriority(), b.getPriority()));
        for (Notification n : queue) n.deliver();
    }

    public void countByType() {
        int email = 0, sms = 0, push = 0;
        for (Notification n : queue) {
            if (n instanceof EmailNotification) email++;
            else if (n instanceof SMSNotification) sms++;
            else if (n instanceof PushNotification) push++;
        }
        System.out.println("Push: " + push + ", SMS: " + sms + ", Email: " + email);
    }
}

public class App {
    public static void main(String[] args) {
        NotificationQueue nq = new NotificationQueue();
        nq.enqueue(new EmailNotification("Welcome to CodeQuest!"));
        nq.enqueue(new SMSNotification("Your OTP is 123456"));
        nq.enqueue(new PushNotification("App update available"));

        nq.deliverAll();
        nq.countByType();
    }
}
